import WidgetKit
import SwiftUI
import AppIntents

struct ToggleEntry: TimelineEntry {
    let date: Date
    let isOn: Bool
}

struct ToggleProvider: TimelineProvider {
    func placeholder(in context: Context) -> ToggleEntry {
        ToggleEntry(date: Date(), isOn: false)
    }
    func getSnapshot(in context: Context, completion: @escaping (ToggleEntry) -> ()) {
        completion(ToggleEntry(date: Date(), isOn: false))
    }
    func getTimeline(in context: Context, completion: @escaping (Timeline<ToggleEntry>) -> ()) {
        let entry = ToggleEntry(date: Date(), isOn: false)
        let timeline = Timeline(entries: [entry], policy: .atEnd)
        completion(timeline)
    }
}

struct ToggleWidgetEntryView: View {
    var entry: ToggleProvider.Entry
    var body: some View {
        Toggle(isOn: .constant(entry.isOn)) {
            Text("Widget Toggle")
        }
        .toggleStyle(.switch)
    }
}

@main
struct ToggleWidget: Widget {
    let kind: String = "ToggleWidget"
    var body: some WidgetConfiguration {
        StaticConfiguration(kind: kind, provider: ToggleProvider()) { entry in
            ToggleWidgetEntryView(entry: entry)
        }
        .configurationDisplayName("Interactive Toggle")
        .description("A widget with a real-time toggle.")
        .supportedFamilies([.systemSmall, .systemMedium])
    }
}

import ActivityKit
import SwiftUI

struct DeliveryAttributes: ActivityAttributes {
    public struct ContentState: Codable, Hashable {
        var status: String
        var driverLocation: String
        var arrivalTime: Date
    }
    var orderID: String
}

struct DeliveryLiveActivity: Widget {
    var body: some WidgetConfiguration {
        ActivityConfiguration(for: DeliveryAttributes.self) { context in
            VStack {
                Text("Order Status: " + context.state.status)
                Text("Driver: " + context.state.driverLocation)
                Text("Arrives in: " + String(Int(context.state.arrivalTime.timeIntervalSinceNow / 60)) + " min")
            }
        } dynamicIsland: { context in
            DynamicIsland {
                DynamicIslandExpandedRegion(.leading) {
                    Text(context.state.status)
                }
                DynamicIslandExpandedRegion(.trailing) {
                    Text(context.state.driverLocation)
                }
                DynamicIslandExpandedRegion(.bottom) {
                    Text("ETA: " + String(Int(context.state.arrivalTime.timeIntervalSinceNow / 60)) + " min")
                }
            } compactLeading: {
                Text("🚚")
            } compactTrailing: {
                Text("🕑")
            } minimal: {
                Text("🚚")
            }
        }
    }
}

