import WidgetKit
import SwiftUI
import AppIntents

struct EventEntry: TimelineEntry {
    let date: Date
    let events: [String]
}

struct EventProvider: TimelineProvider {
    func placeholder(in context: Context) -> EventEntry {
        EventEntry(date: Date(), events: ["No Events"])
    }
    func getSnapshot(in context: Context, completion: @escaping (EventEntry) -> ()) {
        completion(EventEntry(date: Date(), events: ["No Events"]))
    }
    func getTimeline(in context: Context, completion: @escaping (Timeline<EventEntry>) -> ()) {
        let entry = EventEntry(date: Date(), events: ["Meeting at 10am", "Lunch at 12pm"])
        let timeline = Timeline(entries: [entry], policy: .atEnd)
        completion(timeline)
    }
}

struct EventWidgetEntryView: View {
    var entry: EventProvider.Entry
    var body: some View {
        VStack(alignment: .leading) {
            ForEach(entry.events, id: \.self) { event in
                Link(destination: URL(string: "myapp://event/" + event)!) {
                    Text(event)
                }
            }
        }
    }
}

